import (
	"fmt"
	"log"
	"net/http"
	"os"
	"time"
)

const PORT = ":8080"

func debugMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		now := time.Now()
		next.ServeHTTP(w, r)
		log.Printf("handled %s %s in %v", r.Method, r.RequestURI, time.Since(now))
	})
}

func makeStatusHandler(statusCodes []int) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {

		if len(statusCodes) == 0 {
			http.Error(w, "No status codes configured", 500)
			return
		}

		requestedCodeStr := r.URL.Query().Get("code")
		log.Printf("requested code: [%s]", requestedCodeStr)

		requestedCode := 200
		var err error
		if requestedCodeStr != "" {
			requestedCode, err = atoi(requestedCodeStr)
			if err != nil {
				http.Error(w, err.Error(), 400)
				return
			}
		}

		for _, code := range statusCodes {
			if code == requestedCode {
				log.Printf("found configured code %d", code)
				w.WriteHeader(code)
				return
			}
		}
		http.Error(w, "Status code not configured", 404)
	}
}

func getEnvWithDefault(name, def string) string {
	val, ok := os.LookupEnv(name)
	if ok {
		return val
	}
	return def
}

func main() {
	log.Printf("server starting on %s", PORT)
	config := LoadConfig()
	mux := http.NewServeMux()

	// path to test how the middleware handles panic
	mux.Handle("/status", makeStatusHandler(config.StatusCodes))

	mux.Handle("/", http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprint(w, "Hello world! The time is ", time.Now())
	}))

	err := http.ListenAndServe(PORT, debugMiddleware(mux))
	if err != nil {
		log.Fatal(err.Error())
	}
}
